import{_ as t,o as e,c as i,ag as o}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"About Pacs008 | Nederlands","titleTemplate":":title","description":"What Pacs008 does and who it is for.","frontmatter":{"title":"About Pacs008 | Nederlands","description":"What Pacs008 does and who it is for.","lang":"nl-NL","lastUpdated":true,"image":"/logo.svg"},"headers":[],"relativePath":"nl/about/index.md","filePath":"nl/about/index.md","lastUpdated":1774196678000}'),s={name:"nl/about/index.md"};function n(l,a,r,d,c,u){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="about-pacs008" tabindex="-1">About Pacs008 <a class="header-anchor" href="#about-pacs008" aria-label="Permalink to &quot;About Pacs008&quot;">​</a></h1><p>Pacs008 is a Python toolkit for automating ISO 20022 FI-to-FI customer credit transfer workflows. It was designed for teams that need to move from raw operational data to compliant XML quickly, with strong validation and minimal manual formatting.</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><ul><li>Generates XML for <code>pacs.008</code> and adjacent pacs message families</li><li>Validates data and XML against schemas</li><li>Exposes a FastAPI service for automated workflows</li><li>Provides a CLI for local execution and CI pipelines</li><li>Supports structured data sources including CSV, JSON, JSONL, SQLite, and Parquet</li></ul><h2 id="who-it-is-for" tabindex="-1">Who it is for <a class="header-anchor" href="#who-it-is-for" aria-label="Permalink to &quot;Who it is for&quot;">​</a></h2><ul><li>payment operations teams</li><li>platform engineers building internal banking rails</li><li>migration programmes moving toward ISO 20022</li><li>compliance and QA teams validating outbound payment messages</li></ul>',6)])])}const h=t(s,[["render",n]]);export{p as __pageData,h as default};
